#include <stdio.h>
int min(int a, int b) { return a < b ? a : b; }
int matrixMultiplication(int* nums, int n) {
    int dp[n][n];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            dp[i][j] = 0;
        }
    }
    for (int length = 2; length < n; length++) {
        for (int i = 1; i <= n - length; i++) {
            int j = i + length - 1;
            dp[i][j] = 100000000;
            for (int k = i; k < j; k++) {
                int cost = dp[i][k] + dp[k + 1][j] + nums[i - 1] * nums[k] * nums[j];
                dp[i][j] = min(dp[i][j], cost);
            }
        }
    }
    return dp[1][n - 1];
}
int main() {
    int nums[] = {10, 15, 20, 25};
    int n = sizeof(nums) / sizeof(nums[0]);
    printf("%d\n", matrixMultiplication(nums, n));
    return 0;
}

